package com.example.loginprototype;

import android.content.Context;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.text.TextUtils;
import android.util.Patterns;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Toast;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private static final String PREFS_NAME = "login_prefs";
    private static final String KEY_EMAIL = "key_email";
    private static final String KEY_AUTH_TOKEN = "key_auth_token";

    private EditText emailInput;
    private EditText passwordInput;
    private Button loginButton;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        emailInput = findViewById(R.id.emailInput);
        passwordInput = findViewById(R.id.passwordInput);
        loginButton = findViewById(R.id.loginButton);

        SharedPreferences prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        String savedEmail = prefs.getString(KEY_EMAIL, null);
        String savedToken = prefs.getString(KEY_AUTH_TOKEN, null);

        if (!TextUtils.isEmpty(savedEmail) && !TextUtils.isEmpty(savedToken)) {
            emailInput.setText(savedEmail);
            onLoginSuccess(savedEmail, savedToken);
            return;
        }

        loginButton.setOnClickListener(v -> attemptLogin());
    }

    private void attemptLogin() {
        String email = emailInput.getText().toString().trim();
        String password = passwordInput.getText().toString();

        if (TextUtils.isEmpty(email)) {
            emailInput.setError("Email is required");
            return;
        }

        if (!Patterns.EMAIL_ADDRESS.matcher(email).matches()) {
            emailInput.setError("Enter a valid email");
            return;
        }

        if (TextUtils.isEmpty(password)) {
            passwordInput.setError("Password is required");
            return;
        }

        String authToken = authenticateUser(email, password);
        if (authToken != null) {
            saveCredentials(email, authToken);
            onLoginSuccess(email, authToken);
        } else {
            Toast.makeText(this, "Invalid credentials", Toast.LENGTH_SHORT).show();
        }
    }

    private String authenticateUser(String email, String password) {
        if ("demo@example.com".equalsIgnoreCase(email) && "password123".equals(password)) {
            return "demo_auth_token_123456";
        }
        return null;
    }

    private void saveCredentials(String email, String authToken) {
        SharedPreferences prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        prefs.edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_AUTH_TOKEN, authToken)
                .apply();
    }

    private void onLoginSuccess(String email, String authToken) {
        Toast.makeText(this, "Logged in as " + email, Toast.LENGTH_SHORT).show();
        // Continue to the next screen or main app flow here.
        // Example:
        // startActivity(new Intent(this, MainActivity.class));
        // finish();
    }
}